import { Component, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { SeedService } from '../../../data/seed.service';
import { AuthService } from '../../../core/services/auth.service';
import { PortalNotification } from '../../../data/models';

@Component({
  selector: 'app-portal-notifications',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './portal-notifications.component.html',
  styleUrl: './portal-notifications.component.css',
})
export class PortalNotificationsComponent {
  // Local override so "Mark all read" works without mutating the seed store.
  allRead = signal(false);

  notifications = computed<PortalNotification[]>(() => this.seed.portalNotifications());

  unreadCount = computed(() =>
    this.allRead() ? 0 : this.notifications().filter((n) => !n.read).length,
  );

  constructor(public seed: SeedService, public auth: AuthService) {}

  isUnread(n: PortalNotification): boolean {
    return !this.allRead() && !n.read;
  }

  markAllRead(): void {
    this.allRead.set(true);
  }
}
